CREATE OR REPLACE TABLE __SCHEMA_QUALIFIED__.reservations (
    reservation_id STRING,
    customer_id STRING,
    vehicle_id STRING,
    pickup_location_id STRING,
    dropoff_location_id STRING,
    pickup_date DATE,
    dropoff_date DATE,
    status STRING,
    total_amount DOUBLE,
    created_at TIMESTAMP_NTZ
)
USING DELTA
TBLPROPERTIES (delta.enableChangeDataFeed = true);

